PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?date WHERE {
  ?superbowl wdt:P31 wd:Q19317 .
  {
    ?superbowl wdt:P710 wd:Q223243
  } UNION {
    ?superbowl wdt:P1346 wd:Q223243
  }
  .
  ?superbowl wdt:P585 ?date .
}
ORDER BY DESC(?date)
LIMIT 1
